### 5. **Pipeline Instantiation Flow**

**File:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775497462314-kejiff/src/pipelines.js` (lines 3446-3580)

```javascript
export async function pipeline(task, model = null, options = {}) {
  // 1. Resolve task aliases
  task = TASK_ALIASES[task] ?? task;

  // 2. Get pipeline info from SUPPORTED_TASKS
  const pipelineInfo = SUPPORTED_TASKS[task.split('_', 1)[0]];

  // 3. Get default model if not specified
  if (!model) {
    model = pipelineInfo.default.model;
  }

  // 4. Prepare loading classes
  const classes = new Map([
    ['tokenizer', pipelineInfo.tokenizer],     // AutoTokenizer or null
    ['model', pipelineInfo.model],             // AutoModel* class
    ['processor', pipelineInfo.processor],     // AutoProcessor or null
  ]);

  // 5. Load all components in parallel
  const results = await loadItems(classes, model, pretrainedOptions);
  results.task = task;

  // 6. Instantiate pipeline with components
  const pipelineClass = pipelineInfo.pipeline;
  return new pipelineClass(results);
}

async function loadItems(mapping, model, pretrainedOptions) {
  const result = Object.create(null);
  const promises = [];

  for (const [name, cls] of mapping.entries()) {
    if (!cls) continue;

    let promise;
    if (Array.isArray(cls)) {
      // Try multiple classes in order (for fallback models)
      promise = new Promise(async (resolve, reject) => {
        let e;
        for (const c of cls) {
          if (c === null) {
            resolve(null);  // Optional component
            return;
          }
          try {
            resolve(await c.from_pretrained(model, pretrainedOptions));
            return;
          } catch (err) {
            e = err;
          }
        }
        reject(e);
      })
    } else {
      promise = cls.from_pretrained(model, pretrainedOptions);
    }

    result[name] = promise;
    promises.push(promise);
  }

  // Wait for all promises to resolve in parallel
  await Promise.all(promises);

  for (const [name, promise] of Object.entries(result)) {
    result[name] = await promise;
  }

  return result;
}
