### 5. **Pipeline Instantiation Flow**

**File:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775497462314-kejiff/src/pipelines.js` (lines 3446-3580)

```javascript
export async function pipeline(task, model = null, options = {}) {
  // 1. Resolve task aliases
  task = TASK_ALIASES[task] ?? task;

  // 2. Get pipeline info from SUPPORTED_TASKS
  const pipelineInfo = SUPPORTED_TASKS[task.split('_', 1)[0]];

  // 3. Get default model if not specified
  if (!model) {
    model = pipelineInfo.default.model;
  }

  // 4. Prepare loading classes
  const classes = new Map([
    ['tokenizer', pipelineInfo.tokenizer],     // AutoTokenizer or null
    ['model', pipelineInfo.model],             // AutoModel* class
    ['processor', pipelineInfo.processor],     // AutoProcessor or null
  ]);

  // 5. Load all components in parallel
  const results = await loadItems(classes, model, pretrainedOptions);
  results.task = task;

  // 6. Instantiate pipeline with components
  const pipelineClass = pipelineInfo.pipeline;
  return new pipelineClass(results);
}

async function loadItems(mapping, model, pretrainedOptions) {
  const result = Object.create(null);
  const promises = [];

  for (const [name, cls] of mapping.entries()) {
    if (!cls) continue;

    let promise;
    if (Array.isArray(cls)) {
      // Try multiple classes in order (for fallback models)
      promise = new Promise(async (resolve, reject) => {
        let e;
        for (const c of cls) {
          if (c === null) {
            resolve(null);  // Optional component
            return;
          }
          try {
            resolve(await c.from_pretrained(model, pretrainedOptions));
            return;
          } catch (err) {
            e = err;
          }
        }
        reject(e);
      })
    } else {
      promise = cls.from_pretrained(model, pretrainedOptions);
    }

    result[name] = promise;
    promises.push(promise);
  }

  // Wait for all promises to resolve in parallel
  await Promise.all(promises);

  for (const [name, promise] of Object.entries(result)) {
    result[name] = await promise;
  }

  return result;
}
```

---

### 6. **Usage Examples**

#### Image-to-Text:
```javascript
const captioner = await pipeline('image-to-text', 'Xenova/vit-gpt2-image-captioning');
const output = await captioner('image.jpg');
// [{generated_text: "a man and a woman ..."}]
```

#### Document Question Answering:
```javascript
const qa_pipeline = await pipeline('document-question-answering', 'Xenova/donut-base-finetuned-docvqa');
const output = await qa_pipeline(image, "What is the invoice number?");
// [{answer: "12345"}]
```

---

### Key Architecture Insights:

1. **Modular Design**: Processors (image) and Tokenizers (text) are loaded separately and composed together
2. **Flexible Model Selection**: PretrainedMixin uses mappings to select the correct model class based on `model_type` from config
3. **Batch Processing**: Most multimodal pipelines support batching
4. **Token Expansion**: Image-based models use special tokens (like `<image>`) that get expanded based on image patch counts
5. **Feature Merging**: Different models merge image and text features differently:
   - LLaVa: Concatenates directly at the embedding level
   - Florence2: Concatenates embeddings and attention masks
   - VisionEncoderDecoder: Encoder processes image, decoder processes text
6. **Automatic Processor Loading**: AutoProcessor intelligently loads appropriate image processor and tokenizer components based on model config

