/**
 * @typedef {Object} ImageTextToTextSingle
 * @property {string} generated_text The generated text.
 * @typedef {ImageTextToTextSingle[]} ImageTextToTextOutput
 *
 * @callback ImageTextToTextPipelineCallback Generate text from the image(s) and text prompt(s).
 * @param {ImagePipelineInputs} images The input image(s).
 * @param {string|string[]} text The text prompt(s) to condition the generation on.
 * @param {Partial<import('./generation/configuration_utils.js').GenerationConfig>} [options] Additional keyword arguments to pass along to the generate method of the model.
 * @returns {Promise<ImageTextToTextOutput|ImageTextToTextOutput[]>} An array or object containing the generated text(s).
 *
 * @typedef {TextImagePipelineConstructorArgs & ImageTextToTextPipelineCallback & Disposable} ImageTextToTextPipelineType
 */

/**
 * Image-text-to-text pipeline using any `AutoModelForImageTextToText`. This pipeline
 * accepts an image and a text prompt, and generates text conditioned on both.
 *
 * **Example:** Generate a description with `HuggingFaceTB/SmolVLM-256M-Instruct`.
 * ```javascript
 * import { pipeline } from '@huggingface/transformers';
 *
 * const generator = await pipeline('image-text-to-text', 'HuggingFaceTB/SmolVLM-256M-Instruct');
 * const image = 'https://huggingface.co/datasets/huggingface/documentation-images/resolve/main/transformers/tasks/car.jpg';
 * const output = await generator(image, '<image>What is shown in this image?');
 * // [{ generated_text: 'A red sports car ...' }]
 * ```
 */
export class ImageTextToTextPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ImageTextToTextPipelineType} */ (Pipeline)) {

    /**
     * Create a new ImageTextToTextPipeline.
     * @param {TextImagePipelineConstructorArgs} options An object used to instantiate the pipeline.
     */
    constructor(options) {
        super(options);
    }

    /** @type {ImageTextToTextPipelineCallback} */
    async _call(images, text, generate_kwargs = {}) {
        const isBatched = Array.isArray(images);
        const preparedImages = await prepareImages(images);

        if (!Array.isArray(text)) {
            text = [text];
        }

        // Process images and text together through the processor.
        // The processor handles image feature extraction and text tokenization,
        // including expanding image placeholder tokens in the text based on image dimensions.
        const model_inputs = await this.processor(text, preparedImages);

        // Generate output token ids
        const output_ids = /** @type {Tensor} */ (await this.model.generate({
            ...model_inputs,
            ...generate_kwargs,
        }));

        // Decode using the tokenizer embedded in the processor
        const decoded = this.processor.batch_decode(output_ids, {
            skip_special_tokens: true,
        });

        const toReturn = decoded.map(t => ({ generated_text: t.trim() }));
        return isBatched ? [toReturn] : toReturn;
    }
}


